import com.joaomgcd.taskerm.action.java.JavaCodeException;
import java.util.List;
import java.util.Map;
import java.util.HashMap;
import java.util.Iterator;
import java.util.ArrayList;
import org.json.JSONException;
import org.json.JSONObject;
import org.json.JSONArray;

/* Helper function to recursively parse JSON objects and arrays into Java Maps and Lists. */
Object parseJsonValue(Object jsonValue) {
    if (jsonValue instanceof JSONObject) {
        Map map = new HashMap();
        JSONObject obj = (JSONObject) jsonValue;
        Iterator keys = obj.keys();
        while (keys.hasNext()) {
            String key = (String) keys.next();
            map.put(key, parseJsonValue(obj.get(key))); /* Recursive call for nested values. */
        }
        return map;
    } else if (jsonValue instanceof JSONArray) {
        List list = new ArrayList();
        JSONArray array = (JSONArray) jsonValue;
        for (int i = 0; i < array.length(); i++) {
            list.add(parseJsonValue(array.get(i))); /* Recursive call for array elements. */
        }
        return list;
    } else {
        return jsonValue; /* Return primitives, strings, etc. as is. */
    }
}

phone = tasker.getVariable("device_id");
if (phone == null) {
    throw new JavaCodeException("Tasker variable 'device_id' is null. Please ensure it is set.");
}
phone = phone.replaceAll("\\D", "");

httpDataString = tasker.getVariable("http_data");
if (httpDataString == null) {
    throw new JavaCodeException("Tasker variable 'http_data' is null. Please ensure it is set.");
}

data = null;
try {
    /* Parse the entire JSON string using the helper function to convert to Map/List. */
    JSONObject jsonObject = new JSONObject(httpDataString);
    data = (Map) parseJsonValue(jsonObject);
} catch (JSONException e) {
    /* Catch JSON parsing errors and report to Tasker. */
    throw new JavaCodeException("Failed to parse HTTP data as JSON: " + e.getMessage());
}

result = "";

/* Proceed only if data was successfully parsed and contains expected keys. */
if (data != null && data.containsKey("code") && "SUCCESS".equals(data.get("code"))) {
    /* 'results' will now be a java.util.List due to the parseJsonValue helper. */
    results = (List) data.get("results");
    if (results != null) {
        for (i = 0; i < results.size(); i++) {
            d = (Map) results.get(i);
            if (d.containsKey("jid")) {
                jid = (String) d.get("jid");
                if (jid != null) {
                    parts = jid.split("@");
                    if (parts.length > 0) {
                        jidPhone = parts[0].replaceAll("\\D", "");
                        if (jidPhone.equals(phone)) {
                            result = (String) d.get("id");
                            break;
                        }
                    }
                }
            }
        }
    }
}

tasker.setVariable("device_id_output", result);

var msg = local("message");
var saida = msg
  .replace(/\\/g, "\\\\")
  .replace(/"/g, '\\"')
  .replace(/\n/g, "\\n")
  .replace(/\r/g, "\\r");

setLocal("message_escap", saida);

import okhttp3.OkHttpClient;
import okhttp3.Request;
import okhttp3.RequestBody;
import okhttp3.Response;
import okhttp3.MediaType;
import okhttp3.MultipartBody;
import java.io.File;
import com.joaomgcd.taskerm.action.java.JavaCodeException;
import java.util.concurrent.TimeUnit;

deviceId = tasker.getVariable("device_id_output");
phoneNumber = tasker.getVariable("number");
caption = tasker.getVariable("caption");
videoPath = tasker.getVariable("path");
viewOnce = tasker.getVariable("view_once");
compress = tasker.getVariable("compress");
duration = tasker.getVariable("duration_cal");
isForwarded = tasker.getVariable("is_forwarded");

if (deviceId == null || deviceId == void || deviceId.length() == 0) {
    throw new JavaCodeException("Tasker variable %device_id_output is not set.");
}
if (phoneNumber == null || phoneNumber == void || phoneNumber.length() == 0) {
    throw new JavaCodeException("Tasker variable %number (phone number) is not set.");
}
if (videoPath == null || videoPath == void || videoPath.length() == 0) {
    throw new JavaCodeException("Tasker variable %path (video file path) is not set.");
}

fullPhoneNumber = phoneNumber + "@s.whatsapp.net";

videoFile = new File(videoPath);
if (!videoFile.exists()) {
    throw new JavaCodeException("Video file not found at path: " + videoPath);
}
if (!videoFile.canRead()) {
    throw new JavaCodeException("Cannot read video file at path: " + videoPath + ". Check file permissions.");
}

/* Configure OkHttpClient with increased timeouts to prevent SocketTimeoutException. */
client = new OkHttpClient.Builder()
    .connectTimeout(60, TimeUnit.SECONDS) /* Set connection timeout to 60 seconds. */
    .readTimeout(60, TimeUnit.SECONDS)    /* Set read timeout to 60 seconds. */
    .writeTimeout(60, TimeUnit.SECONDS)   /* Set write timeout to 60 seconds. */
    .build();

multipartBodyBuilder = new MultipartBody.Builder()
    .setType(MultipartBody.FORM);

multipartBodyBuilder.addFormDataPart("phone", fullPhoneNumber);
multipartBodyBuilder.addFormDataPart("caption", caption != null ? caption : "");
multipartBodyBuilder.addFormDataPart("view_once", viewOnce != null ? viewOnce : "false");
multipartBodyBuilder.addFormDataPart("compress", compress != null ? compress : "false");
multipartBodyBuilder.addFormDataPart("duration", duration != null ? duration : "0");
multipartBodyBuilder.addFormDataPart("is_forwarded", isForwarded != null ? isForwarded : "false");

fileName = videoFile.getName();
fileExtension = "";
dotIndex = fileName.lastIndexOf('.');
if (dotIndex > 0 && dotIndex < fileName.length() - 1) {
    fileExtension = fileName.substring(dotIndex + 1).toLowerCase();
}

mimeType = "application/octet-stream";

if (fileExtension.equals("mp4")) {
    mimeType = "video/mp4";
} else if (fileExtension.equals("3gp")) {
    mimeType = "video/3gp";
} else {
    tasker.log("Warning: Unrecognized video file extension: " + fileExtension + ". Defaulting to application/octet-stream.");
}

videoMediaType = MediaType.parse(mimeType);
videoRequestBody = RequestBody.create(videoMediaType, videoFile);
multipartBodyBuilder.addFormDataPart("video", videoFile.getName(), videoRequestBody);

requestBody = multipartBodyBuilder.build();

request = new Request.Builder()
    .url("http://localhost:3000/send/video")
    .addHeader("Authorization", "Basic dXNlcjE6cGFzczE=")
    .addHeader("X-Device-Id", deviceId)
    .post(requestBody)
    .build();

response = client.newCall(request).execute();

responseBody = response.body().string();

tasker.log("Server Response Code: " + response.code());
tasker.log("Server Response Body: " + responseBody);

return responseBody;

