var number = local('number');
var question = local('poll_question');
var max_answer = local('max_answe');
var duration = local('duration_cal');

var options = [];
var erroSequencia = false;
var encontrouVazio = false;

for (var i = 1; i <= 12; i++) {
    var valor = local('poll' + i);
    var preenchido = (valor !== null && valor !== undefined && valor.trim() !== "");

    if (preenchido) {
        if (encontrouVazio) {
            erroSequencia = true;
            break;
        }
        options.push(valor);
    } else {
        encontrouVazio = true;
    }
}

if (!number || !question || erroSequencia || options.length < 2) {
    setLocal('poll_exit', "");
    setLocal('status_erro', erroSequencia ? "ERRO_SEQUENCIA" : "DADOS_INSUFICIENTES");
} else {
    var resultado = {
        "phone": number,
        "question": question,
        "options": options,
        "max_answer": parseInt(max_answer) || 1,
        "duration": parseInt(duration) || 86400
    };

    setLocal('poll_exit', JSON.stringify(resultado));
    setLocal('status_erro', "OK");
}

