List todasMensagens = new ArrayList();
int maxVariaveis = 100;

for (int i = 1; i <= maxVariaveis; i++) {
    String nomeVariavel;
    if (i == 1) {
        nomeVariavel = "message";
    } else {
        nomeVariavel = "message" + i;
    }

    String valor = tasker.getVariable(nomeVariavel);

    if (valor != null && valor != void && valor.trim().length() > 0) {
        todasMensagens.add(valor.trim());
    }
}

tasker.setVariable("status_array", String.join("\n-----\n", todasMensagens));

tasker.setVariable("status_count", new Integer(todasMensagens.size()));

