import java.util.List;
import java.util.ArrayList;
import java.lang.StringBuffer;

int MAX_ITERATIONS = 100;

List paths = new ArrayList();
List captions = new ArrayList();

int i = 1;
while (true) {
    if (i > MAX_ITERATIONS) break;

    String key = (i == 1) ? "path" : "path" + i;
    String val = tasker.getVariable(key);
    if (val == null || val == void || "".equals(val) || key.equals(val)) break;
    paths.add(val);
    i++;
}

int max = paths.size();

i = 1;
while (i <= max) {
    String key = (i == 1) ? "caption" : "caption" + i;
    String val = tasker.getVariable(key);
    if (val == null || val == void || key.equals(val)) {
        captions.add("");
    } else {
        captions.add(val);
    }
    i++;
}

StringBuffer pathsBuffer = new StringBuffer();
for (int j = 0; j < paths.size(); j++) {
    pathsBuffer.append((String) paths.get(j));
    if (j < paths.size() - 1) {
        pathsBuffer.append("\n-----\n");
    }
}
tasker.setVariable("paths", pathsBuffer.toString());

StringBuffer captionsBuffer = new StringBuffer();
for (int j = 0; j < captions.size(); j++) {
    captionsBuffer.append((String) captions.get(j));
    if (j < captions.size() - 1) {
        captionsBuffer.append("\n-----\n");
    }
}
tasker.setVariable("captions", captionsBuffer.toString());

List missing = new ArrayList();
for (int j = 0; j < paths.size(); j++) {
    String cap = (String) captions.get(j);
    if (cap == null || "".equals(cap.trim())) {
        missing.add(new Integer(j + 1));
    }
}

String errorMsg = "";
if (missing.size() > 0) {
    StringBuffer missingBuffer = new StringBuffer();
    for (int j = 0; j < missing.size(); j++) {
        missingBuffer.append(missing.get(j));
        if (j < missing.size() - 1) {
            missingBuffer.append(", ");
        }
    }
    errorMsg = "Faltando legenda(s) para a(s) imagem(ns): " + missingBuffer.toString();
}
tasker.setVariable("error", errorMsg);

